node -e "
const jobs = require('./scenarios/fieldwork/fixtures/jobs.json');
const today = '2026-07-14';

const open = jobs.filter(j => j.completedAt === null);
console.log('total jobs:', jobs.length);
console.log('open jobs (completedAt null):', open.length);

const statusCounts = {};
for (const j of jobs) statusCounts[j.status] = (statusCounts[j.status]||0)+1;
console.log('status counts (all jobs):', statusCounts);

const overdue = open.filter(j => j.status === 'overdue');
console.log('overdue count:', overdue.length, overdue.map(j=>j.id));

const unassigned = open.filter(j => j.techId === null);
console.log('unassigned (open, no tech):', unassigned.length, unassigned.map(j=>j.id));

const inProgress = open.filter(j => j.status === 'en-route' || j.status === 'on-site');
console.log('en-route/on-site (in progress):', inProgress.length, inProgress.map(j=>({id:j.id,status:j.status})));

// SLA at risk: open, not already overdue, slaDue is today or earlier than today+1 (i.e. due today)
const slaAtRisk = open.filter(j => j.status !== 'overdue' && j.slaDue <= today);
console.log('SLA at risk (slaDue <= today, not overdue status):', slaAtRisk.length, slaAtRisk.map(j=>({id:j.id,slaDue:j.slaDue,status:j.status})));

// scheduled today jobs
const scheduledToday = jobs.filter(j => j.scheduledStart && j.scheduledStart.slice(0,10) === today);
console.log('scheduled today (scheduledStart date = today):', scheduledToday.length, scheduledToday.map(j=>({id:j.id,status:j.status})));

const doneCount = jobs.filter(j=>j.status==='done').length;
console.log('done count:', doneCount);

const scheduledCount = jobs.filter(j=>j.status==='scheduled').length;
console.log('scheduled(status) count:', scheduledCount);
"

